    try:
        content = fac.read_file("bob", "document1.txt")
        print(f"Bob read: {content}")
    except PermissionError as e:
        print(e)
    
    try:
        content = fac.read_file("charlie", "document1.txt")
        print(f"Charlie read: {content}")
    except PermissionError as e:
        print(f"Error: {e}")
    
    print(f"\nAlice's permissions: {fac.list_user_permissions('alice')}")
